# solution.py
# TeamCollaborationManager - standard library only, ASCII only, Python 3.12
import copy
import csv
import io
import threading
from dataclasses import dataclass
from datetime import datetime
from enum import Enum
from typing import Optional


# ---------------------------------------------------------------------------
# Enums
# ---------------------------------------------------------------------------

class TaskStatus(Enum):
    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class UserRole(Enum):
    MEMBER = "member"
    ADMIN = "admin"


class ReportFormat(Enum):
    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    TEAM_PERFORMANCE = "team_performance"
    PROJECT_PROGRESS = "project_progress"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exceptions
# ---------------------------------------------------------------------------

class TeamCollaborationError(Exception):
    pass


class ValidationError(TeamCollaborationError):
    pass


class NotFoundError(TeamCollaborationError):
    pass


class AuthorizationError(TeamCollaborationError):
    pass


class DuplicateError(TeamCollaborationError):
    pass


class ConflictError(TeamCollaborationError):
    pass


# ---------------------------------------------------------------------------
# Dataclasses (mutable)
# ---------------------------------------------------------------------------

@dataclass
class Attachment:
    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class User:
    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    id: int
    name: str
    description: str
    start_date: datetime
    end_date: datetime
    owner_id: int


@dataclass
class Task:
    id: int
    project_id: int
    title: str
    status: TaskStatus
    assignee_id: Optional[int]
    deadline: Optional[datetime]
    started_at: Optional[datetime]
    completed_at: Optional[datetime]


@dataclass
class Message:
    id: int
    author_id: int
    body: str
    project_id: Optional[int]
    task_id: Optional[int]
    parent_id: Optional[int]
    attachments: list
    created_at: datetime
    edited_at: Optional[datetime]


@dataclass
class Rating:
    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str
    task_id: Optional[int]
    created_at: datetime


# ---------------------------------------------------------------------------
# Store helper - holds reference to shared lock
# ---------------------------------------------------------------------------

class _Store:
    def __init__(self, lock):
        self._lock = lock


# ---------------------------------------------------------------------------
# TeamCollaborationManager
# ---------------------------------------------------------------------------

class TeamCollaborationManager:

    def __init__(self, now=None):
        self._now = now if now is not None else datetime.now
        self._lock = threading.RLock()
        self._next_id = 1

        # Sub-stores all sharing the same lock (tests assert id equality)
        self.users = _Store(self._lock)
        self.projects = _Store(self._lock)
        self.tasks = _Store(self._lock)
        self.messages = _Store(self._lock)
        self.performance = _Store(self._lock)
        self.reports = _Store(self._lock)

        # Internal data
        self._users = {}             # id -> User
        self._users_by_name = {}     # username -> id
        self._users_by_email = {}    # email -> id

        self._projects = {}          # id -> Project

        self._tasks = {}             # id -> Task
        self._tasks_by_project = {}  # project_id -> set of task_ids
        self._tasks_by_assignee = {} # user_id -> set of task_ids

        self._messages = {}               # id -> Message
        self._messages_by_project = {}    # project_id -> list of msg_ids
        self._messages_by_task = {}       # task_id -> list of msg_ids

        self._ratings = {}               # id -> Rating
        self._ratings_by_ratee = {}      # user_id -> list of rating_ids

    def _alloc_id(self):
        # Must be called under lock
        uid = self._next_id
        self._next_id += 1
        return uid

    # -----------------------------------------------------------------------
    # Users
    # -----------------------------------------------------------------------

    def register_user(self, username, email, role=UserRole.MEMBER):
        with self._lock:
            if isinstance(username, str):
                username = username.strip()
            if not username:
                raise ValidationError("Username cannot be empty")
            if not email or not email.strip():
                raise ValidationError("Email cannot be empty")
            if "@" not in email:
                raise ValidationError("Email must contain @")
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole instance")
            if username in self._users_by_name:
                raise DuplicateError("Duplicate username: {}".format(username))
            if email in self._users_by_email:
                raise DuplicateError("Duplicate email: {}".format(email))

            uid = self._alloc_id()
            user = User(
                id=uid, username=username, email=email,
                role=role, created_at=self._now()
            )
            self._users[uid] = user
            self._users_by_name[username] = uid
            self._users_by_email[email] = uid
            return copy.deepcopy(user)

    def get_user(self, user_id):
        with self._lock:
            if user_id not in self._users:
                raise NotFoundError("User not found: {}".format(user_id))
            return copy.deepcopy(self._users[user_id])

    def list_users(self):
        with self._lock:
            return [copy.deepcopy(u)
                    for u in sorted(self._users.values(), key=lambda u: u.id)]

    def update_user(self, user_id, username=None, email=None, role=None):
        with self._lock:
            if user_id not in self._users:
                raise NotFoundError("User not found: {}".format(user_id))
            user = self._users[user_id]

            if username is not None:
                if username in self._users_by_name and self._users_by_name[username] != user_id:
                    raise DuplicateError("Duplicate username: {}".format(username))

            if email is not None:
                if "@" not in email:
                    raise ValidationError("Email must contain @")
                if email in self._users_by_email and self._users_by_email[email] != user_id:
                    raise DuplicateError("Duplicate email: {}".format(email))

            if role is not None:
                if not isinstance(role, UserRole):
                    raise ValidationError("role must be a UserRole instance")

            if username is not None:
                del self._users_by_name[user.username]
                user.username = username
                self._users_by_name[username] = user_id

            if email is not None:
                del self._users_by_email[user.email]
                user.email = email
                self._users_by_email[email] = user_id

            if role is not None:
                user.role = role

            return copy.deepcopy(user)

    def delete_user(self, user_id):
        with self._lock:
            if user_id not in self._users:
                raise NotFoundError("User not found: {}".format(user_id))

            for project in self._projects.values():
                if project.owner_id == user_id:
                    raise ConflictError("User owns a project")

            task_ids = self._tasks_by_assignee.get(user_id, set())
            for tid in task_ids:
                task = self._tasks.get(tid)
                if task and task.status != TaskStatus.COMPLETED:
                    raise ConflictError("User has open tasks")

            user = self._users.pop(user_id)
            del self._users_by_name[user.username]
            del self._users_by_email[user.email]

    # -----------------------------------------------------------------------
    # Projects
    # -----------------------------------------------------------------------

    def create_project(self, name, start_date, end_date, owner_id, description=""):
        with self._lock:
            if owner_id not in self._users:
                raise NotFoundError("Owner not found: {}".format(owner_id))
            if not name or not name.strip():
                raise ValidationError("Project name cannot be empty")
            if end_date < start_date:
                raise ValidationError("end_date must be >= start_date")

            pid = self._alloc_id()
            project = Project(
                id=pid, name=name, description=description,
                start_date=start_date, end_date=end_date, owner_id=owner_id
            )
            self._projects[pid] = project
            self._tasks_by_project[pid] = set()
            return copy.deepcopy(project)

    def get_project(self, project_id):
        with self._lock:
            if project_id not in self._projects:
                raise NotFoundError("Project not found: {}".format(project_id))
            return copy.deepcopy(self._projects[project_id])

    def list_projects(self):
        with self._lock:
            return [copy.deepcopy(p)
                    for p in sorted(self._projects.values(), key=lambda p: p.id)]

    def update_project(self, project_id, name=None, description=None,
                       start_date=None, end_date=None):
        with self._lock:
            if project_id not in self._projects:
                raise NotFoundError("Project not found: {}".format(project_id))
            project = self._projects[project_id]

            if name is not None and not name.strip():
                raise ValidationError("Project name cannot be empty")

            eff_start = start_date if start_date is not None else project.start_date
            eff_end = end_date if end_date is not None else project.end_date
            if eff_end < eff_start:
                raise ValidationError("end_date must be >= start_date")

            if name is not None:
                project.name = name
            if description is not None:
                project.description = description
            if start_date is not None:
                project.start_date = start_date
            if end_date is not None:
                project.end_date = end_date

            return copy.deepcopy(project)

    def delete_project(self, project_id):
        with self._lock:
            if project_id not in self._projects:
                raise NotFoundError("Project not found: {}".format(project_id))

            # Cascade: delete tasks (and their messages + assignee index)
            for tid in list(self._tasks_by_project.get(project_id, set())):
                task = self._tasks.pop(tid, None)
                if task is None:
                    continue
                if task.assignee_id is not None:
                    self._tasks_by_assignee.get(task.assignee_id, set()).discard(tid)
                # Delete messages attached to this task
                for mid in self._messages_by_task.pop(tid, []):
                    self._messages.pop(mid, None)

            self._tasks_by_project.pop(project_id, None)

            # Cascade: delete project-level messages
            for mid in self._messages_by_project.pop(project_id, []):
                self._messages.pop(mid, None)

            del self._projects[project_id]

    # -----------------------------------------------------------------------
    # Tasks
    # -----------------------------------------------------------------------

    def create_task(self, project_id, title, assignee_id=None, deadline=None):
        with self._lock:
            if project_id not in self._projects:
                raise NotFoundError("Project not found: {}".format(project_id))
            if not title or not title.strip():
                raise ValidationError("Task title cannot be empty")
            if assignee_id is not None and assignee_id not in self._users:
                raise NotFoundError("Assignee not found: {}".format(assignee_id))

            project = self._projects[project_id]
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("Deadline before project start")

            tid = self._alloc_id()
            task = Task(
                id=tid, project_id=project_id, title=title,
                status=TaskStatus.NOT_STARTED, assignee_id=assignee_id,
                deadline=deadline, started_at=None, completed_at=None
            )
            self._tasks[tid] = task
            self._tasks_by_project.setdefault(project_id, set()).add(tid)
            if assignee_id is not None:
                self._tasks_by_assignee.setdefault(assignee_id, set()).add(tid)
            return copy.deepcopy(task)

    def get_task(self, task_id):
        with self._lock:
            if task_id not in self._tasks:
                raise NotFoundError("Task not found: {}".format(task_id))
            return copy.deepcopy(self._tasks[task_id])

    def list_tasks_by_project(self, project_id):
        with self._lock:
            if project_id not in self._projects:
                raise NotFoundError("Project not found: {}".format(project_id))
            ids = self._tasks_by_project.get(project_id, set())
            tasks = [self._tasks[i] for i in ids if i in self._tasks]
            return [copy.deepcopy(t) for t in sorted(tasks, key=lambda t: t.id)]

    def list_tasks_by_assignee(self, assignee_id):
        with self._lock:
            if assignee_id not in self._users:
                raise NotFoundError("User not found: {}".format(assignee_id))
            ids = self._tasks_by_assignee.get(assignee_id, set())
            tasks = [self._tasks[i] for i in ids if i in self._tasks]
            return [copy.deepcopy(t) for t in sorted(tasks, key=lambda t: t.id)]

    def assign_task(self, task_id, assignee_id):
        with self._lock:
            if task_id not in self._tasks:
                raise NotFoundError("Task not found: {}".format(task_id))
            if assignee_id not in self._users:
                raise NotFoundError("User not found: {}".format(assignee_id))
            task = self._tasks[task_id]
            if task.assignee_id is not None:
                self._tasks_by_assignee.get(task.assignee_id, set()).discard(task_id)
            self._tasks_by_assignee.setdefault(assignee_id, set()).add(task_id)
            task.assignee_id = assignee_id
            return copy.deepcopy(task)

    def reassign_task(self, task_id, new_assignee_id):
        # Same semantics as assign_task; RLock allows re-entry
        with self._lock:
            return self.assign_task(task_id, new_assignee_id)

    def unassign_task(self, task_id):
        with self._lock:
            if task_id not in self._tasks:
                raise NotFoundError("Task not found: {}".format(task_id))
            task = self._tasks[task_id]
            if task.assignee_id is not None:
                self._tasks_by_assignee.get(task.assignee_id, set()).discard(task_id)
            task.assignee_id = None
            return copy.deepcopy(task)

    def set_deadline(self, task_id, deadline):
        with self._lock:
            if task_id not in self._tasks:
                raise NotFoundError("Task not found: {}".format(task_id))
            task = self._tasks[task_id]
            if deadline is not None:
                project = self._projects[task.project_id]
                if deadline < project.start_date:
                    raise ValidationError("Deadline before project start")
            task.deadline = deadline
            return copy.deepcopy(task)

    def update_status(self, task_id, status):
        with self._lock:
            if task_id not in self._tasks:
                raise NotFoundError("Task not found: {}".format(task_id))
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus instance")
            task = self._tasks[task_id]
            now = self._now()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            else:  # NOT_STARTED
                task.started_at = None
                task.completed_at = None
            task.status = status
            return copy.deepcopy(task)

    # -----------------------------------------------------------------------
    # Messaging
    # -----------------------------------------------------------------------

    def post_message(self, author_id, body, project_id=None, task_id=None,
                     parent_id=None, attachments=None):
        with self._lock:
            # 1. Validate author
            if author_id not in self._users:
                raise NotFoundError("Author not found: {}".format(author_id))

            # 2. Exactly one target
            if project_id is None and task_id is None:
                raise ValidationError("Provide exactly one of project_id or task_id")
            if project_id is not None and task_id is not None:
                raise ValidationError("Provide exactly one of project_id or task_id")

            # 3. Target exists
            if project_id is not None and project_id not in self._projects:
                raise NotFoundError("Project not found: {}".format(project_id))
            if task_id is not None and task_id not in self._tasks:
                raise NotFoundError("Task not found: {}".format(task_id))

            # 4. Body check
            has_attachments = bool(attachments)
            if not body and not has_attachments:
                raise ValidationError("Body required when no attachments")

            # 5. Parent check
            if parent_id is not None and parent_id not in self._messages:
                raise NotFoundError("Parent not found: {}".format(parent_id))

            att_list = []
            if attachments:
                for filename, data in attachments:
                    att_list.append(Attachment(
                        filename=filename, size=len(data),
                        uploaded_by=author_id, uploaded_at=self._now()
                    ))

            mid = self._alloc_id()
            msg = Message(
                id=mid, author_id=author_id, body=body,
                project_id=project_id, task_id=task_id,
                parent_id=parent_id, attachments=att_list,
                created_at=self._now(), edited_at=None
            )
            self._messages[mid] = msg
            if project_id is not None:
                self._messages_by_project.setdefault(project_id, []).append(mid)
            if task_id is not None:
                self._messages_by_task.setdefault(task_id, []).append(mid)
            return copy.deepcopy(msg)

    def edit_message(self, message_id, editor_id, new_body):
        with self._lock:
            if message_id not in self._messages:
                raise NotFoundError("Message not found: {}".format(message_id))
            msg = self._messages[message_id]
            if msg.author_id != editor_id:
                raise AuthorizationError("Only the author can edit")
            if not new_body:
                raise ValidationError("New body cannot be empty")
            msg.body = new_body
            msg.edited_at = self._now()
            return copy.deepcopy(msg)

    def add_attachment(self, message_id, user_id, filename, data):
        with self._lock:
            if message_id not in self._messages:
                raise NotFoundError("Message not found: {}".format(message_id))
            msg = self._messages[message_id]
            if msg.author_id != user_id:
                raise AuthorizationError("Only the author can add attachments")
            if not filename:
                raise ValidationError("Filename cannot be empty")
            msg.attachments.append(Attachment(
                filename=filename, size=len(data),
                uploaded_by=user_id, uploaded_at=self._now()
            ))
            return copy.deepcopy(msg)

    def list_messages_by_project(self, project_id):
        with self._lock:
            if project_id not in self._projects:
                raise NotFoundError("Project not found: {}".format(project_id))
            ids = self._messages_by_project.get(project_id, [])
            msgs = [self._messages[i] for i in ids if i in self._messages]
            return [copy.deepcopy(m) for m in sorted(msgs, key=lambda m: m.id)]

    def list_messages_by_task(self, task_id):
        with self._lock:
            if task_id not in self._tasks:
                raise NotFoundError("Task not found: {}".format(task_id))
            ids = self._messages_by_task.get(task_id, [])
            msgs = [self._messages[i] for i in ids if i in self._messages]
            return [copy.deepcopy(m) for m in sorted(msgs, key=lambda m: m.id)]

    def delete_message(self, message_id, user_id):
        with self._lock:
            if message_id not in self._messages:
                raise NotFoundError("Message not found: {}".format(message_id))
            msg = self._messages[message_id]
            if msg.author_id != user_id:
                raise AuthorizationError("Only the author can delete")
            if msg.project_id is not None:
                lst = self._messages_by_project.get(msg.project_id, [])
                if message_id in lst:
                    lst.remove(message_id)
            if msg.task_id is not None:
                lst = self._messages_by_task.get(msg.task_id, [])
                if message_id in lst:
                    lst.remove(message_id)
            del self._messages[message_id]

    # -----------------------------------------------------------------------
    # Performance
    # -----------------------------------------------------------------------

    def get_completion_rate(self, user_id):
        with self._lock:
            if user_id not in self._users:
                raise NotFoundError("User not found: {}".format(user_id))
            ids = self._tasks_by_assignee.get(user_id, set())
            total = len(ids)
            if total == 0:
                return 0.0
            completed = sum(
                1 for i in ids
                if i in self._tasks and self._tasks[i].status == TaskStatus.COMPLETED
            )
            return completed / total

    def get_average_completion_time(self, user_id):
        with self._lock:
            if user_id not in self._users:
                raise NotFoundError("User not found: {}".format(user_id))
            ids = self._tasks_by_assignee.get(user_id, set())
            times = []
            for i in ids:
                t = self._tasks.get(i)
                if t and t.status == TaskStatus.COMPLETED and t.started_at and t.completed_at:
                    times.append((t.completed_at - t.started_at).total_seconds())
            return sum(times) / len(times) if times else None

    def submit_rating(self, rater_id, ratee_id, score, feedback="", task_id=None):
        with self._lock:
            if rater_id == ratee_id:
                raise ConflictError("Cannot rate yourself")
            if score < 1 or score > 5:
                raise ValidationError("Score must be 1-5")
            if rater_id not in self._users:
                raise NotFoundError("Rater not found: {}".format(rater_id))
            if ratee_id not in self._users:
                raise NotFoundError("Ratee not found: {}".format(ratee_id))
            if task_id is not None and task_id not in self._tasks:
                raise NotFoundError("Task not found: {}".format(task_id))

            rid = self._alloc_id()
            rating = Rating(
                id=rid, rater_id=rater_id, ratee_id=ratee_id,
                score=score, feedback=feedback, task_id=task_id,
                created_at=self._now()
            )
            self._ratings[rid] = rating
            self._ratings_by_ratee.setdefault(ratee_id, []).append(rid)
            return copy.deepcopy(rating)

    def get_ratings_summary(self, user_id):
        with self._lock:
            if user_id not in self._users:
                raise NotFoundError("User not found: {}".format(user_id))
            ids = self._ratings_by_ratee.get(user_id, [])
            ratings = [copy.deepcopy(self._ratings[i]) for i in ids if i in self._ratings]
            count = len(ratings)
            average = sum(r.score for r in ratings) / count if count else 0.0
            return {"count": count, "average": average, "ratings": ratings}

    def get_user_dashboard(self, user_id):
        with self._lock:
            if user_id not in self._users:
                raise NotFoundError("User not found: {}".format(user_id))
            ids = self._tasks_by_assignee.get(user_id, set())
            tasks = [self._tasks[i] for i in ids if i in self._tasks]

            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
            not_started = sum(1 for t in tasks if t.status == TaskStatus.NOT_STARTED)
            completion_rate = completed / total if total else 0.0

            times = [
                (t.completed_at - t.started_at).total_seconds()
                for t in tasks
                if t.status == TaskStatus.COMPLETED and t.started_at and t.completed_at
            ]
            avg_time = sum(times) / len(times) if times else None

            rating_ids = self._ratings_by_ratee.get(user_id, [])
            ratings = [self._ratings[i] for i in rating_ids if i in self._ratings]
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count if rating_count else 0.0
            )

            return {
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": completion_rate,
                "average_completion_time": avg_time,
                "rating_count": rating_count,
                "rating_average": rating_average,
            }

    # -----------------------------------------------------------------------
    # Reports
    # -----------------------------------------------------------------------

    def project_progress_report(self, project_id):
        with self._lock:
            if project_id not in self._projects:
                raise NotFoundError("Project not found: {}".format(project_id))

            ids = self._tasks_by_project.get(project_id, set())
            tasks = [self._tasks[i] for i in ids if i in self._tasks]
            total = len(tasks)
            status_counts = {
                TaskStatus.NOT_STARTED.value: 0,
                TaskStatus.IN_PROGRESS.value: 0,
                TaskStatus.COMPLETED.value: 0,
            }
            now = self._now()
            overdue = 0
            per_assignee = {}

            for t in tasks:
                status_counts[t.status.value] += 1
                if (t.deadline is not None
                        and now > t.deadline
                        and t.status != TaskStatus.COMPLETED):
                    overdue += 1
                if t.assignee_id is not None:
                    aid = t.assignee_id
                    if aid not in per_assignee:
                        per_assignee[aid] = {"total": 0, "completed": 0}
                    per_assignee[aid]["total"] += 1
                    if t.status == TaskStatus.COMPLETED:
                        per_assignee[aid]["completed"] += 1

            completion_rate = (
                status_counts[TaskStatus.COMPLETED.value] / total if total else 0.0
            )
            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completion_rate,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id=None):
        with self._lock:
            if project_id is not None and project_id not in self._projects:
                raise NotFoundError("Project not found: {}".format(project_id))

            if project_id is not None:
                ids = self._tasks_by_project.get(project_id, set())
                scope = [self._tasks[i] for i in ids if i in self._tasks]
            else:
                scope = list(self._tasks.values())

            user_tasks = {}
            for t in scope:
                if t.assignee_id is not None:
                    user_tasks.setdefault(t.assignee_id, []).append(t)

            rows = []
            for uid, utasks in user_tasks.items():
                user = self._users.get(uid)
                if user is None:
                    continue
                total = len(utasks)
                completed = sum(1 for t in utasks if t.status == TaskStatus.COMPLETED)
                completion_rate = completed / total if total else 0.0
                times = [
                    (t.completed_at - t.started_at).total_seconds()
                    for t in utasks
                    if t.status == TaskStatus.COMPLETED and t.started_at and t.completed_at
                ]
                avg_time = sum(times) / len(times) if times else None
                rating_ids = self._ratings_by_ratee.get(uid, [])
                ratings = [self._ratings[i] for i in rating_ids if i in self._ratings]
                rc = len(ratings)
                ra = sum(r.score for r in ratings) / rc if rc else 0.0
                rows.append({
                    "user_id": uid,
                    "username": user.username,
                    "total_tasks": total,
                    "completed_tasks": completed,
                    "completion_rate": completion_rate,
                    "average_completion_time": avg_time,
                    "rating_count": rc,
                    "rating_average": ra,
                })

            return {"report_type": ReportType.TEAM_PERFORMANCE.value, "rows": rows}

    def individual_performance_report(self, user_id):
        with self._lock:
            if user_id not in self._users:
                raise NotFoundError("User not found: {}".format(user_id))
            ids = self._tasks_by_assignee.get(user_id, set())
            tasks = [self._tasks[i] for i in ids if i in self._tasks]
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            task_summaries = [
                {
                    "id": t.id, "title": t.title, "status": t.status.value,
                    "deadline": str(t.deadline), "started_at": str(t.started_at),
                    "completed_at": str(t.completed_at),
                }
                for t in sorted(tasks, key=lambda t: t.id)
            ]
            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "tasks": task_summaries,
            }

    def export_report(self, report, format):
        with self._lock:
            if not isinstance(report, dict):
                raise ValidationError("report must be a dict")
            if not isinstance(format, ReportFormat):
                raise ValidationError("format must be a ReportFormat instance")
            if format == ReportFormat.CSV:
                return self._export_csv(report)
            return self._export_pdf(report)

    def _export_csv(self, report):
        output = io.StringIO()
        writer = csv.writer(output)
        if "rows" in report:
            rows = report["rows"]
            if rows:
                header = list(rows[0].keys())
                writer.writerow(header)
                for row in rows:
                    writer.writerow([str(row.get(k, "")) for k in header])
            else:
                writer.writerow(["report_type"])
                writer.writerow([report.get("report_type", "")])
        else:
            writer.writerow(["key", "value"])
            for k, v in report.items():
                if isinstance(v, dict):
                    for dk, dv in v.items():
                        writer.writerow(["{}_{}".format(k, dk), str(dv)])
                elif isinstance(v, list):
                    writer.writerow([k, "{} items".format(len(v))])
                else:
                    writer.writerow([k, str(v)])
        return output.getvalue()

    def _export_pdf(self, report):
        # Minimal PDF starting with required %PDF- signature
        return (
            b"%PDF-1.4\n"
            b"1 0 obj\n<< /Type /Catalog /Pages 2 0 R >>\nendobj\n"
            b"2 0 obj\n<< /Type /Pages /Kids [3 0 R] /Count 1 >>\nendobj\n"
            b"3 0 obj\n<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] >>\nendobj\n"
            b"xref\ntrailer\n<< /Size 4 /Root 1 0 R >>\n%%EOF\n"
        )
